import { NextRequest, NextResponse } from 'next/server'
import { z } from 'zod'
import { prisma } from '@/lib/db/prisma'
import { brandContextToBusinessProfile } from '@/lib/agent/brand-adapter'
import { generateEpisode } from '@/lib/agent/generate-episode'
import { AIProviderSchema, SocialPlatformSchema } from '@/lib/agent/types'
import { getActiveProvider } from '@/lib/settings/api-key'

const RequestSchema = z.object({ brandContextId: z.string(), topic: z.string().min(2), platforms: z.array(SocialPlatformSchema).min(1), provider: AIProviderSchema.optional() })

export async function POST(request: NextRequest) {
  try {
    const body = await request.json()
    const parsed = RequestSchema.safeParse(body)
    if (!parsed.success) return NextResponse.json({ error: 'Invalid request', details: parsed.error.flatten() }, { status: 400 })
    const { brandContextId, topic, platforms } = parsed.data
    const provider = parsed.data.provider ?? (await getActiveProvider())
    const brand = await prisma.brandContext.findUnique({ where: { id: brandContextId } })
    if (!brand) return NextResponse.json({ error: 'Business not found' }, { status: 404 })
    const business = brandContextToBusinessProfile(brand)
    const result = await generateEpisode({ provider, business, topic, platforms })
    const saved = await prisma.contentPackage.create({ data: { brandContextId, topic, provider, platforms, strategyNote: result.payload.strategyNote, agentReasoning: result.payload.agentReasoning, content: result.payload.content } })
    await prisma.activityLog.create({ data: { type: 'CONTENT_GENERATED', summary: `Generated content package for "${topic}" (${platforms.join(', ')})`, details: { packageId: saved.id, platforms, provider, model: result.model } } })
    return NextResponse.json({ package: { id: saved.id, businessId: saved.brandContextId, topic: saved.topic, provider: saved.provider, platforms: saved.platforms, strategyNote: saved.strategyNote, agentReasoning: saved.agentReasoning, content: saved.content, createdAt: saved.createdAt.toISOString() }, model: result.model, usage: result.usage })
  } catch (error: unknown) {
    console.error('Generate failed:', error)
    const message = error instanceof Error ? error.message : 'Generation failed'
    return NextResponse.json({ error: message }, { status: 500 })
  }
}

import { serve } from "inngest/next";
import { inngest } from "@/lib/inngest/client";
import { functions } from "@/lib/inngest/functions";

export const { GET, POST, PUT } = serve({
  client: inngest,
  functions,
});

import { NextRequest, NextResponse } from 'next/server'
import { prisma } from '@/lib/db/prisma'

type RouteContext = { params: Promise<{ id: string }> }

export async function GET(_request: NextRequest, context: RouteContext) {
  try {
    const { id } = await context.params
    const pkg = await prisma.contentPackage.findUnique({ where: { id }, include: { brandContext: { select: { companyName: true } } } })
    if (!pkg) return NextResponse.json({ error: 'Package not found' }, { status: 404 })
    return NextResponse.json({ package: { id: pkg.id, businessId: pkg.brandContextId, businessName: pkg.brandContext.companyName, topic: pkg.topic, provider: pkg.provider, platforms: pkg.platforms, strategyNote: pkg.strategyNote, agentReasoning: pkg.agentReasoning, content: pkg.content, createdAt: pkg.createdAt.toISOString() } })
  } catch (error) {
    console.error('Failed to load package:', error)
    return NextResponse.json({ error: 'Failed to load package' }, { status: 500 })
  }
}

import { NextRequest, NextResponse } from 'next/server'
import { prisma } from '@/lib/db/prisma'

export async function GET(request: NextRequest) {
  try {
    const { searchParams } = new URL(request.url)
    const brandContextId = searchParams.get('brandContextId')
    const limit = Math.min(parseInt(searchParams.get('limit') || '20', 10), 50)
    const packages = await prisma.contentPackage.findMany({ where: brandContextId ? { brandContextId } : undefined, orderBy: { createdAt: 'desc' }, take: limit, include: { brandContext: { select: { companyName: true } } } })
    return NextResponse.json({ packages: packages.map((p) => ({ id: p.id, businessId: p.brandContextId, businessName: p.brandContext.companyName, topic: p.topic, provider: p.provider, platforms: p.platforms, strategyNote: p.strategyNote, agentReasoning: p.agentReasoning, content: p.content, createdAt: p.createdAt.toISOString() })) })
  } catch (error) {
    console.error('Failed to list packages:', error)
    return NextResponse.json({ error: 'Failed to load packages' }, { status: 500 })
  }
}

import { NextRequest, NextResponse } from 'next/server'
import { z } from 'zod'
import { AIProviderSchema, type AIProvider } from '@/lib/agent/types'
import { getApiKeyStatus, saveApiKey, removeApiKey, getActiveProvider, saveActiveProvider, getMonthlyBudget, saveMonthlyBudget } from '@/lib/settings/api-key'
import { AI_PROVIDERS } from '@/lib/constants/ai-providers'

export async function GET() {
  try {
    const [activeProvider, monthlyBudgetUsd, providers] = await Promise.all([getActiveProvider(), getMonthlyBudget(), Promise.all(AI_PROVIDERS.map(async (p) => ({ id: p.id, label: p.label, ...(await getApiKeyStatus(p.id)) })))]);
    return NextResponse.json({ activeProvider, monthlyBudgetUsd, providers })
  } catch (error) {
    console.error('Failed to load settings:', error)
    return NextResponse.json({ error: 'Failed to load settings' }, { status: 500 })
  }
}

const PostSchema = z.object({ provider: AIProviderSchema.optional(), apiKey: z.string().min(8).optional(), activeProvider: AIProviderSchema.optional(), monthlyBudgetUsd: z.number().min(0).nullable().optional() })

export async function POST(request: NextRequest) {
  try {
    const body = await request.json()
    const parsed = PostSchema.safeParse(body)
    if (!parsed.success) return NextResponse.json({ error: 'Invalid settings payload' }, { status: 400 })
    if (parsed.data.apiKey && parsed.data.provider) await saveApiKey(parsed.data.provider, parsed.data.apiKey)
    if (parsed.data.activeProvider) await saveActiveProvider(parsed.data.activeProvider)
    if (parsed.data.monthlyBudgetUsd !== undefined) await saveMonthlyBudget(parsed.data.monthlyBudgetUsd)
    return GET()
  } catch (error) {
    console.error('Failed to save settings:', error)
    return NextResponse.json({ error: 'Failed to save settings' }, { status: 500 })
  }
}

export async function DELETE(request: NextRequest) {
  try {
    const { searchParams } = new URL(request.url)
    const provider = searchParams.get('provider') as AIProvider | null
    if (!provider || !AIProviderSchema.safeParse(provider).success) return NextResponse.json({ error: 'Provider required' }, { status: 400 })
    await removeApiKey(provider)
    return GET()
  } catch (error) {
    console.error('Failed to remove API key:', error)
    return NextResponse.json({ error: 'Failed to remove API key' }, { status: 500 })
  }
}

import { NextResponse } from 'next/server'
import { prisma } from '@/lib/db/prisma'

export async function GET() {
  try {
    const [logs, summary] = await Promise.all([
      prisma.apiUsageLog.findMany({ orderBy: { createdAt: 'desc' }, take: 30 }),
      prisma.apiUsageLog.aggregate({ _sum: { totalTokens: true, estimatedCostUsd: true }, _count: true }),
    ])
    return NextResponse.json({ totalCalls: summary._count, totalTokens: summary._sum.totalTokens || 0, estimatedCostUsd: summary._sum.estimatedCostUsd || 0, recentLogs: logs })
  } catch (error) {
    return NextResponse.json({ error: 'Failed to load usage data' }, { status: 500 })
  }
}

@import "tailwindcss";

:root {
  --font-sans: var(--font-geist-sans);
  --font-mono: var(--font-geist-mono);

  /* Professional dark executive palette (zinc-based) */
  --bg-950: #09090b;
  --bg-900: #111113;
  --bg-800: #18181b;
  --bg-700: #27272a;
  --bg-600: #3f3f46;

  --text-50: #fafafa;
  --text-100: #f4f4f5;
  --text-200: #e4e4e7;
  --text-300: #d4d4d8;
  --text-400: #a1a1aa;
  --text-500: #71717a;

  --accent: #3b82f6;        /* Blue 500 for CTAs */
  --accent-hover: #2563eb;

  --success: #22c55e;
  --warning: #eab308;
  --danger: #ef4444;

  --border: #27272a;
  --ring: #3b82f6;
}

@theme inline {
  --color-background: var(--bg-950);
  --color-foreground: var(--text-100);
  --font-sans: var(--font-geist-sans);
  --font-mono: var(--font-geist-mono);
}

/* Base */
html {
  color-scheme: dark;
}

body {
  background: var(--bg-950);
  color: var(--text-100);
  font-family: var(--font-geist-sans);
}

/* Professional UI Primitives */
.card {
  background: var(--bg-900);
  border: 1px solid var(--border);
  border-radius: 16px;
}

.btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 8px;
  padding: 10px 18px;
  font-size: 14px;
  font-weight: 500;
  border-radius: 12px;
  transition: all 0.1s ease;
  cursor: pointer;
}

.btn-primary {
  background: var(--text-50);
  color: var(--bg-950);
  border: none;
}

.btn-primary:hover {
  background: #e4e4e7;
}

.btn-secondary {
  background: var(--bg-800);
  color: var(--text-100);
  border: 1px solid var(--border);
}

.btn-secondary:hover {
  background: var(--bg-700);
  border-color: var(--bg-600);
}

.btn-ghost {
  background: transparent;
  color: var(--text-300);
  border: 1px solid transparent;
}

.btn-ghost:hover {
  background: var(--bg-800);
  color: var(--text-100);
}

.btn-danger {
  background: var(--danger);
  color: white;
  border: none;
}

.input {
  background: var(--bg-950);
  border: 1px solid var(--border);
  color: var(--text-100);
  padding: 10px 14px;
  border-radius: 10px;
  font-size: 14px;
  transition: border-color 0.1s;
}

.input:focus {
  outline: none;
  border-color: var(--ring);
  box-shadow: 0 0 0 1px var(--ring);
}

.textarea {
  background: var(--bg-950);
  border: 1px solid var(--border);
  color: var(--text-100);
  padding: 14px 16px;
  border-radius: 12px;
  font-size: 14px;
  line-height: 1.6;
  resize: vertical;
}

.textarea:focus {
  outline: none;
  border-color: var(--ring);
  box-shadow: 0 0 0 1px var(--ring);
}

.badge {
  display: inline-flex;
  align-items: center;
  padding: 2px 10px;
  font-size: 11px;
  font-weight: 600;
  letter-spacing: 0.5px;
  border-radius: 9999px;
  text-transform: uppercase;
}

.badge-pending {
  background: #27272a;
  color: #eab308;
}

.badge-approved {
  background: #052e16;
  color: #4ade80;
}

.badge-draft {
  background: #27272a;
  color: var(--text-400);
}

/* Dashboard specific */
.nav-link {
  padding: 8px 14px;
  border-radius: 10px;
  font-size: 14px;
  color: var(--text-400);
  transition: all 0.1s;
}

.nav-link:hover {
  color: var(--text-100);
  background: var(--bg-800);
}

.nav-link.active {
  color: var(--text-50);
  background: var(--bg-800);
  font-weight: 500;
}

/* Left sidebar navigation */
.sidebar-link {
  display: flex;
  align-items: center;
  gap: 10px;
  padding: 10px 12px;
  border-radius: 12px;
  font-size: 13px;
  color: var(--text-400);
  transition: all 0.12s ease;
  text-decoration: none;
}

.sidebar-link:hover {
  color: var(--text-100);
  background: var(--bg-800);
}

.sidebar-link.active {
  color: var(--text-50);
  background: var(--bg-800);
  font-weight: 500;
  box-shadow: inset 0 0 0 1px var(--border);
}

.sidebar-sublink {
  display: flex;
  align-items: center;
  gap: 8px;
  padding: 8px 10px;
  border-radius: 10px;
  font-size: 12px;
  color: var(--text-500);
  transition: all 0.12s ease;
  text-decoration: none;
}

.sidebar-sublink:hover {
  color: var(--text-200);
  background: var(--bg-800);
}

.sidebar-sublink.active {
  color: var(--text-100);
  background: var(--bg-800);
  font-weight: 500;
}

.app-sidebar {
  box-shadow: 8px 0 32px -8px rgb(0 0 0 / 0.35);
}

/* Modal */
.modal {
  background: var(--bg-900);
  border: 1px solid var(--border);
  border-radius: 20px;
  box-shadow: 0 25px 50px -12px rgb(0 0 0 / 0.4);
}

/* Scrollbars (subtle) */
::-webkit-scrollbar {
  width: 6px;
  height: 6px;
}
::-webkit-scrollbar-track {
  background: var(--bg-900);
}
::-webkit-scrollbar-thumb {
  background: var(--bg-600);
  border-radius: 3px;
}
::-webkit-scrollbar-thumb:hover {
  background: var(--bg-500);
}

